// MARK: - WKScriptMessageHandler

extension HybridWebViewController: WKScriptMessageHandler {
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard message.name == WebViewConfig.messageHandlerName else { return }
        
        guard let bodyString = message.body as? String,
              let bodyData = bodyString.data(using: .utf8),
              let json = try? JSONSerialization.jsonObject(with: bodyData) as? [String: Any],
              let typeString = json["type"] as? String else {
            print("[NativeBridge] Invalid message format")
            return
        }
        
        let data = json["data"] as? [String: Any] ?? [:]
        let callbackId = json["callbackId"] as? String
        
        guard let messageType = BridgeMessageType(rawValue: typeString) else {
            print("[NativeBridge] Unknown message type: \(typeString)")
            sendCallback(callbackId: callbackId, success: false, data: ["error": "Unknown message type"])
            return
        }
        
        print("[NativeBridge] Received message: \(messageType.rawValue)")
        
        switch messageType {
        case .camera:
            handleCameraRequest(data: data, callbackId: callbackId)
        case .pushNotification:
            handlePushNotificationRequest(data: data, callbackId: callbackId)
        case .inAppPurchase:
            handleInAppPurchaseRequest(data: data, callbackId: callbackId)
        case .hapticFeedback:
            handleHapticFeedback(data: data)
        case .shareContent:
            handleShareContent(data: data, callbackId: callbackId)
        case .getDeviceInfo:
            handleGetDeviceInfo(callbackId: callbackId)
        case .log:
            handleLog(data: data)
        }
    }
}

// MARK: - Camera Handling

extension HybridWebViewController: UIImagePickerControllerDelegate, UINavigationControllerDelegate {
    
    private static var cameraCallbackId: String?
    
    private func handleCameraRequest(data: [String: Any], callbackId: String?) {
        HybridWebViewController.cameraCallbackId = callbackId
        
        let sourceType: UIImagePickerController.SourceType
        let source = data["source"] as? String ?? "camera"
        
        switch source {
        case "camera":
            sourceType = .camera
        case "photoLibrary":
            sourceType = .photoLibrary
        default:
            sourceType = .camera
        }
        
        // Check camera permission
        if sourceType == .camera {
            let status = AVCaptureDevice.authorizationStatus(for: .video)
            switch status {
            case .notDetermined:
                AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
                    DispatchQueue.main.async {
                        if granted {
                            self?.presentImagePicker(sourceType: sourceType)
                        } else {
                            self?.sendCallback(callbackId: callbackId, success: false, data: ["error": "Camera permission denied"])
                        }
                    }
                }
                return
            case .denied, .restricted:
                sendCallback(callbackId: callbackId, success: false, data: ["error": "Camera permission denied"])
                promptOpenSettings(message: "Camera access is required. Please enable it in Settings.")
                return
            case .authorized:
                break
            @unknown default:
                break
            }
        }
        
        presentImagePicker(sourceType: sourceType)
    }
    
    private func presentImagePicker(sourceType: UIImagePickerController.SourceType) {
        guard UIImagePickerController.isSourceTypeAvailable(sourceType) else {
            sendCallback(callbackId: HybridWebViewController.cameraCallbackId, success: false, data: ["error": "Source type not available"])
            return
        }
        
        let picker = UIImagePickerController()
        picker.delegate = self
        picker.sourceType = sourceType
        picker.allowsEditing = true
        picker.modalPresentationStyle = .fullScreen
        present(picker, animated: true)
    }
    
    func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey : Any]) {
        picker.dismiss(animated: true)
        
        let image = (info[.editedImage] as? UIImage) ?? (info[.originalImage] as? UIImage)
        
        guard let selectedImage = image,
              let imageData = selectedImage.jpegData(compressionQuality: 0.7) else {
            sendCallback(callbackId: HybridWebViewController.cameraCallbackId, success: false, data: ["error": "Failed to process image"])
            return
        }
        
        let base64String = imageData.base64EncodedString()
        let responseData: [String: Any] = [
            "imageBase64": "data:image/jpeg;base64,\(base64String)",
            "width": selectedImage.size.width,
            "height": selectedImage.size.height
        ]
        
        sendCallback(callbackId: HybridWebViewController.cameraCallbackId, success: true, data: responseData)
    }
    
    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        picker.dismiss(animated: true)
        sendCallback(callbackId: HybridWebViewController.cameraCallbackId, success: false, data: ["error": "User cancelled"])
    }
    
    private func promptOpenSettings(message: String) {
        let alert = UIAlertController(title: "Permission Required", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Open Settings", style: .default) { _ in
            if let settingsURL = URL(string: UIApplication.openSettingsURLString) {
                UIApplication.shared.open(settingsURL)
            }
        })
        present(alert, animated: true)
    }
}

// MARK: - Push Notification Handling

extension HybridWebViewController {
    
    private func handlePushNotificationRequest(data: [String: Any], callbackId: String?) {
        let action = data["action"] as? String ?? "requestPermission"
        
        switch action {
        case "requestPermission":
            requestPushPermission(callbackId: callbackId)
        case "getToken":
            getPushToken(callbackId: callbackId)
        case "getStatus":
            getPushStatus(callbackId: callbackId)
        default:
            sendCallback(callbackId: callbackId, success: false, data: ["error": "Unknown push action"])
        }
    }
    
    private func requestPushPermission(callbackId: String?) {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { [weak self] granted, error in
            if let error = error {
                self?.sendCallback(callbackId: callbackId, success: false, data: ["error": error.localizedDescription])
                return
            }
            
            DispatchQueue.main.async {
                if granted {
                    UIApplication.shared.registerForRemoteNotifications()
                }
                self?.sendCallback(callbackId: callbackId, success: true, data: ["granted": granted])
            }
        }
    }
    
    private func getPushToken(callbackId: String?) {
        // Token is usually stored by AppDelegate when received
        if let token = UserDefaults.standard.string(forKey: "pushDeviceToken") {
            sendCallback(callbackId: callbackId, success: true, data: ["token": token])
        } else {
            sendCallback(callbackId: callbackId, success: false, data: ["error": "Push token not available"])
        }
    }
    
    private func getPushStatus(callbackId: String?) {
        UNUserNotificationCenter.current().getNotificationSettings { [weak self] settings in
            let status: String
            switch settings.authorizationStatus {
            case .authorized: status = "authorized"
            case .denied: status = "denied"
            case .notDetermined: status = "notDetermined"
            case .provisional: status = "provisional"
            case .ephemeral: status = "ephemeral"
            @unknown default: status = "unknown"
            }
            self?.sendCallback(callbackId: callbackId, success: true, data: ["status": status])
        }
    }
    
    // Call this from AppDelegate when push token is received
    func updatePushToken(_ token: String) {
        UserDefaults.standard.set(token, forKey: "pushDeviceToken")
        sendEventToWeb(eventName: "pushTokenUpdated", data: ["token": token])
    }
    
    // Call this from AppDelegate when push notification is received
    func handlePushNotification(userInfo: [AnyHashable: Any]) {
        var data: [String: Any] = [:]
        for (key, value) in userInfo {
            if let stringKey = key as? String {
                data[stringKey] = value
            }
        }
        sendEventToWeb(eventName: "pushNotificationReceived", data: data)
    }
}

// MARK: - In-App Purchase Handling

extension HybridWebViewController: InAppPurchaseManagerDelegate {
    
    private func handleInAppPurchaseRequest(data: [String: Any], callbackId: String?) {
        let action = data["action"] as? String ?? ""
        
        switch action {
        case "getProducts":
            let productIds = data["productIds"] as? [String] ?? []
            purchaseManager?.fetchProducts(productIds: Set(productIds), callbackId: callbackId)
            
        case "purchase":
            guard let productId = data["productId"] as? String else {
                sendCallback(callbackId: callbackId, success: false, data: ["error": "Product ID required"])
                return
            }
            purchaseManager?.purchaseProduct(productId: productId, callbackId: callbackId)
            
        case "restore":
            purchaseManager?.restorePurchases(callbackId: callbackId)
            
        default:
            sendCallback(callbackId: callbackId, success: false, data: ["error": "Unknown purchase action"])
        }
    }
    
    func purchaseCompleted(callbackId: String?, productId: String, transactionId: String, receipt: String?) {
        let data: [String: Any] = [
            "productId": productId,
            "transactionId": transactionId,
            "receipt": receipt ?? ""
        ]
        sendCallback(callbackId: callbackId, success: true, data: data)
    }
    
    func purchaseFailed(callbackId: String?, error: String) {
        sendCallback(callbackId: callbackId, success: false, data: ["error": error])
    }
    
    func productsLoaded(callbackId: String?, products: [[String: Any]]) {
        sendCallback(callbackId: callbackId, success: true, data: ["products": products])
    }
    
    func purchasesRestored(callbackId: String?, restoredProducts: [String]) {
        sendCallback(callbackId: callbackId, success: true, data: ["restoredProducts": restoredProducts])
    }
}

// MARK: - Haptic Feedback

extension HybridWebViewController {
    
    private func handleHapticFeedback(data: [String: Any]) {
        let style = data["style"] as? String ?? "medium"
        
        switch style {
        case "light":
            let generator = UIImpactFeedbackGenerator(style: .light)
            generator.impactOccurred()
        case "medium":
            let generator = UIImpactFeedbackGenerator(style: .medium)
            generator.impactOccurred()
        case "heavy":
            let generator = UIImpactFeedbackGenerator(style: .heavy)
            generator.impactOccurred()
        case "success":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.success)
        case "warning":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.warning)
        case "error":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.error)
        case "selection":
            let generator = UISelectionFeedbackGenerator()
            generator.selectionChanged()
        default:
            let generator = UIImpactFeedbackGenerator(style: .medium)
            generator.impactOccurred()
        }
    }
}

// MARK: - Share Content

extension HybridWebViewController {
    
    private func handleShareContent(data: [String: Any], callbackId: String?) {
        var items: [Any] = []
        
        if let text = data["text"] as? String {
            items.append(text)
        }
        if let urlString = data["url"] as? String, let url = URL(string: urlString) {
            items.append(url)
        }
        if let title = data["title"] as? String, items.isEmpty {
            items.append(title)
        }
        
        guard !items.isEmpty else {
            sendCallback(callbackId: callbackId, success: false, data: ["error": "No content to share"])
            return
        }
        
        let activityVC = UIActivityViewController(activityItems: items, applicationActivities: nil)
        activityVC.completionWithItemsHandler = { [weak self] activityType, completed, _, error in
            if let error = error {
                self?.sendCallback(callbackId: callbackId, success: false, data: ["error": error.localizedDescription])
            } else {
                self?.sendCallback(callbackId: callbackId, success: completed, data: [
                    "completed": completed,
                    "activityType": activityType?.rawValue ?? ""
                ])
            }
        }
        
        // iPad support
        if let popover = activityVC.popoverPresentationController {
            popover.sourceView = view
            popover.sourceRect = CGRect(x: view.bounds.midX, y: view.bounds.midY, width: 0, height: 0)
        }
        
        present(activityVC, animated: true)
    }
}

