// MARK: - WKNavigationDelegate

extension HybridWebViewController: WKNavigationDelegate {
    
    func webView(_ webView: WKWebView, didStartProvisionalNavigation navigation: WKNavigation!) {
        activityIndicator.startAnimating()
        removeErrorView()
    }
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        activityIndicator.stopAnimating()
        
        // Re-inject bridge if needed after navigation
        let checkBridge = "typeof window.NativeBridge !== 'undefined'"
        webView.evaluateJavaScript(checkBridge) { [weak self] result, _ in
            if let exists = result as? Bool, !exists {
                // Bridge doesn't exist, it will be re-injected via userScript on next page load
                print("[NativeBridge] Bridge will be injected on next page load")
            }
        }
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        activityIndicator.stopAnimating()
        handleNavigationError(error)
    }
    
    func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
        activityIndicator.stopAnimating()
        handleNavigationError(error)
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }
        
        // Handle special URL schemes
        let scheme = url.scheme?.lowercased() ?? ""
        switch scheme {
        case "tel", "mailto", "sms":
            UIApplication.shared.open(url)
            decisionHandler(.cancel)
            return
        case "itms-apps", "itms-appss":
            UIApplication.shared.open(url)
            decisionHandler(.cancel)
            return
        default:
            break
        }
        
        // Handle external links (open in Safari)
        if navigationAction.navigationType == .linkActivated,
           let host = url.host,
           !WebViewConfig.allowedDomains.contains(where: { host.contains($0) }) {
            UIApplication.shared.open(url)
            decisionHandler(.cancel)
            return
        }
        
        decisionHandler(.allow)
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationResponse: WKNavigationResponse, decisionHandler: @escaping (WKNavigationResponsePolicy) -> Void) {
        if let httpResponse = navigationResponse.response as? HTTPURLResponse {
            if httpResponse.statusCode >= 400 {
                print("[WebView] HTTP Error: \(httpResponse.statusCode)")
            }
        }
        decisionHandler(.allow)
    }
    
    private func handleNavigationError(_ error: Error) {
        let nsError = error as NSError
        
        // Ignore cancelled requests
        if nsError.code == NSURLErrorCancelled { return }
        
        print("[WebView] Navigation error: \(error.localizedDescription)")
        
        if nsError.code == NSURLErrorNotConnectedToInternet ||
            nsError.code == NSURLErrorNetworkConnectionLost {
            showErrorView(message: "No internet connection.\nPlease check your network settings.")
        } else if nsError.code == NSURLErrorTimedOut {
            showErrorView(message: "Connection timed out.\nPlease try again.")
        } else {
            showErrorView(message: "Something went wrong.\n\(error.localizedDescription)")
        }
    }
}

// MARK: - WKUIDelegate

extension HybridWebViewController: WKUIDelegate {
    
    // Handle JavaScript alert()
    func webView(_ webView: WKWebView, runJavaScriptAlertPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping () -> Void) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler()
        })
        present(alert, animated: true)
    }
    
    // Handle JavaScript confirm()
    func webView(_ webView: WKWebView, runJavaScriptConfirmPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (Bool) -> Void) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(false)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(true)
        })
        present(alert, animated: true)
    }
    
    // Handle JavaScript prompt()
    func webView(_ webView: WKWebView, runJavaScriptTextInputPanelWithPrompt prompt: String, defaultText: String?, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (String?) -> Void) {
        let alert = UIAlertController(title: nil, message: prompt, preferredStyle: .alert)
        alert.addTextField { textField in
            textField.text = defaultText
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(nil)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(alert.textFields?.first?.text)
        })
        present(alert, animated: true)
    }
    
    // Handle window.open() - create new webview or open in same
    func webView(_ webView: WKWebView, createWebViewWith configuration: WKWebViewConfiguration, for navigationAction: WKNavigationAction, windowFeatures: WKWindowFeatures) -> WKWebView? {
        if navigationAction.targetFrame == nil || !(navigationAction.targetFrame!.isMainFrame) {
            webView.load(navigationAction.request)
        }
        return nil
    }
}

// MARK: - LeakAvoider (prevents retain cycle with WKScriptMessageHandler)

class LeakAvoider: NSObject, WKScriptMessageHandler {
    weak var delegate: WKScriptMessageHandler?
    
    init(delegate: WKScriptMessageHandler) {
        self.delegate = delegate
        super.init()
    }
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        delegate?.userContentController(userContentController, didReceive: message)
    }
}

// MARK: - InAppPurchaseManager

protocol InAppPurchaseManagerDelegate: AnyObject {
    func purchaseCompleted(callbackId: String?, productId: String, transactionId: String, receipt: String?)
    func purchaseFailed(callbackId: String?, error: String)
    func productsLoaded(callbackId: String?, products: [[String: Any]])
    func purchasesRestored(callbackId: String?, restoredProducts: [String])
}

class InAppPurchaseManager: NSObject, SKProductsRequestDelegate, SKPaymentTransactionObserver {
    
    weak var delegate: InAppPurchaseManagerDelegate?
    
    private var products: [String: SKProduct] = [:]
    private var fetchCallbackId: String?
    private var purchaseCallbackId: String?
    private var restoreCallbackId: String?
    private var restoredProductIds: [String] = []
    
    override init() {
        super.init()
        SKPaymentQueue.default().add(self)
    }
    
    deinit {
        SKPaymentQueue.default().remove(self)
    }
    
    func fetchProducts(productIds: Set<String>, callbackId: String?) {
        fetchCallbackId = callbackId
        let request = SKProductsRequest(productIdentifiers: productIds)
        request.delegate = self
        request.start()
    }
    
    func purchaseProduct(productId: String, callbackId: String?) {
        purchaseCallbackId = callbackId
        
        guard SKPaymentQueue.canMakePayments() else {
            delegate?.purchaseFailed(callbackId: callbackId, error: "In-app purchases are disabled on this device")
            return
        }
        
        guard let product = products[productId] else {
            delegate?.purchaseFailed(callbackId: callbackId, error: "Product not found. Please fetch products first.")
            return
        }
        
        let payment = SKPayment(product: product)
        SKPaymentQueue.default().add(payment)
    }
    
    func restorePurchases(callbackId: String?) {
        restoreCallbackId = callbackId
        restoredProductIds = []
        SKPaymentQueue.default().restoreCompletedTransactions()
    }
    
    // MARK: - SKProductsRequestDelegate
    
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        var productList: [[String: Any]] = []
        
        for product in response.products {
            products[product.productIdentifier] = product
            
            let formatter = NumberFormatter()
            formatter.numberStyle = .currency
            formatter.locale = product.priceLocale
            
            let productInfo: [String: Any] = [
                "productId": product.productIdentifier,
                "title": product.localizedTitle,
                "description": product.localizedDescription,
                "price": product.price.doubleValue,
                "priceFormatted": formatter.string(from: product.price) ?? "",
                "currencyCode": product.priceLocale.currencyCode ?? ""
            ]
            productList.append(productInfo)
        }
        
        if !response.invalidProductIdentifiers.isEmpty {
            print("[IAP] Invalid product IDs: \(response.invalidProductIdentifiers)")
        }
        
        delegate?.productsLoaded(callbackId: fetchCallbackId, products: productList)
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        delegate?.purchaseFailed(callbackId: fetchCallbackId, error: error.localizedDescription)
    }
    
    // MARK: - SKPaymentTransactionObserver
    
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                let receipt = getReceipt()
                delegate?.purchaseCompleted(
                    callbackId: purchaseCallbackId,
                    productId: transaction.payment.productIdentifier,
                    transactionId: transaction.transactionIdentifier ?? "",
                    receipt: receipt
                )
                queue.finishTransaction(transaction)
                
            case .failed:
                let errorMessage = transaction.error?.localizedDescription ?? "Purchase failed"
                let skError = transaction.error as? SKError
                if skError?.code == .paymentCancelled {
                    delegate?.purchaseFailed(callbackId: purchaseCallbackId, error: "User cancelled")
                } else {
                    delegate?.purchaseFailed(callbackId: purchaseCallbackId, error: errorMessage)
                }
                queue.finishTransaction(transaction)
                
            case .restored:
                restoredProductIds.append(transaction.payment.productIdentifier)
                queue.finishTransaction(transaction)
                
            case .deferred:
                print("[IAP] Transaction deferred for: \(transaction.payment.productIdentifier)")
                
            case .purchasing:
                break
                
            @unknown default:
                break
            }
        }
    }
    
    func paymentQueueRestoreCompletedTransactionsFinished(_ queue: SKPaymentQueue) {
        delegate?.purchasesRestored(callbackId: restoreCallbackId, restoredProducts: restoredProductIds)
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, restoreCompletedTransactionsFailedWithError error: Error) {
        delegate?.purchaseFailed(callbackId: restoreCallbackId, error: error.localizedDescription)
    }
    
    private func getReceipt() -> String? {
        guard let receiptURL = Bundle.main.appStoreReceiptURL,
              let receiptData = try? Data(contentsOf: receiptURL) else {
            return nil
        }
        return receiptData.base64EncodedString()
    }
}

// MARK: - SceneDelegate / AppDelegate Integration Helper

extension HybridWebViewController {
    
    /// Call from AppDelegate to handle universal links
    func handleUniversalLink(url: URL) {
        webView.load(URLRequest(url: url))
    }
    
    /// Call from AppDelegate to handle deep links
    func handleDeepLink(path: String, params: [String: String]? = nil) {
        var urlString = WebViewConfig.baseURL + path
        if let params = params, !params.isEmpty {
            let queryString = params.map { "\($0.key)=\($0.value)" }.joined(separator: "&")
            urlString += "?\(queryString)"
        }
        if let url = URL(string: urlString) {
            webView.load(URLRequest(url: url))
        }
    }
}